#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d\n", &T)!=1) return 0;
    char buf[1024];
    for(int tc=0; tc<T; ++tc){
        if(!fgets(buf, sizeof(buf), stdin)) buf[0]='\0';
        size_t len = strlen(buf);
        if(len>0 && buf[len-1]=='\n') buf[--len]='\0'; // remove trailing newline
        printf("[");
        for(size_t i=0;i<len;++i){
            printf("'%c'", buf[i]);
            if(i+1!=len) printf(", ");
        }
        printf("]\n");
    }
    return 0;
}

