code.Java:
import java.io.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String tLine = br.readLine();
        int T = Integer.parseInt(tLine.trim());
        for(int tc=0; tc<T; ++tc){
            String s = br.readLine();
            if(s == null) s = ""; // safety
            StringBuilder sb = new StringBuilder();
            sb.append('[');
            for(int i=0;i<s.length();++i){
                sb.append('\'').append(s.charAt(i)).append('\'');
                if(i+1!=s.length()) sb.append(", ");
            }
            sb.append(']');
            System.out.println(sb.toString());
        }
    }
}

code.JavaScript:
const fs = require('fs');
const data = fs.readFileSync(0, 'utf-8').split('\n');
const T = parseInt(data[0].trim(), 10);
let out = [];
for(let i=1;i<=T;i++){
  let s = data[i] !== undefined ? data[i] : '';
  // remove possible carriage return from Windows line endings
  if(s.endsWith('\r')) s = s.slice(0, -1);
  const parts = [];
  for(const ch of s){
    parts.push(`'${ch}'`);
  }
  out.push('[' + parts.join(', ') + ']');
}
console.log(out.join('\n'));
